1	/**
2	 * Pod HTTP client — the compute pod IS the app (see sdk/org/libs/cli/src/server/serve.ts).
3	 *
4	 * The pod itself does no auth: Envoy validates the gateway JWT at the edge and routes on the
5	 * `sub` claim to `lmthing.user-<id>.svc`. So every call here just carries the bearer token and
6	 * talks to the chat origin. Locally (`lmthing serve`) pass base=http://localhost:8080 and no token.
7	 */
8	
9	export class Pod {
10	  constructor({ base, token }) {
11	    this.base = base;
12	    this.token = token;
13	  }
14	
15	  async req(method, path, body, { raw = false } = {}) {
16	    // A scaled-to-zero pod answers with `504 {waking:true}` while the Envoy activator boots
17	    // it; that is a transient, not the endpoint's verdict. Retry idempotent-ish calls until
18	    // the pod is warm (bounded), so a read that lands on a cold pod self-heals instead of
19	    // throwing a spurious failure mid-scenario.
20	    for (let attempt = 0; ; attempt++) {
21	      const res = await fetch(`${this.base}${path}`, {
22	        method,
23	        headers: {
24	          ...(body !== undefined ? { 'content-type': 'application/json' } : {}),
25	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
26	        },
27	        ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
28	      });
29	      const text = await res.text();
30	      let parsed = text;
31	      try {
32	        parsed = JSON.parse(text);
33	      } catch {
34	        /* raw text (e.g. an ASCII state tree) */
35	      }
36	      const waking =
37	        res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
38	      if (waking && attempt < 20) {
39	        await new Promise((r) => setTimeout(r, 3000));
40	        continue;
41	      }
42	      if (!res.ok && !raw) {
43	        const err = new Error(`${method} ${path} → ${res.status}: ${text.slice(0, 400)}`);
44	        err.status = res.status;
45	        err.body = parsed;
46	        throw err;
47	      }
48	      return raw ? { status: res.status, body: parsed } : parsed;
49	    }
50	  }
51	
52	  // ── projects ────────────────────────────────────────────────────────────
53	  listProjects = () => this.req('GET', '/api/projects');
54	  createProject = (name) => this.req('POST', '/api/projects', { name });
55	  deleteProject = (id) => this.req('DELETE', `/api/projects/${id}`);
56	  listSpaces = (projectId) => this.req('GET', `/api/projects/${projectId}/spaces`);
57	  listIntegrations = (projectId) => this.req('GET', `/api/projects/${projectId}/integrations`);
58	  projectSessions = (projectId) => this.req('GET', `/api/projects/${projectId}/sessions`);
59	
60	  // ── files (the whole point: assert what the agents actually WROTE) ───────
61	  fsTree = () => this.req('GET', '/api/fs/tree');
62	  readFile = (path) => this.req('GET', `/api/fs/read?path=${encodeURIComponent(path)}`);
63	  writeFile = (path, content) => this.req('PUT', '/api/fs/write', { path, content });
64	
65	  // ── store ───────────────────────────────────────────────────────────────
66	  storeSpaces = () => this.req('GET', '/api/store/spaces');
67	  installSpace = (spaceId, projectId = 'user', force = false) =>
68	    this.req('POST', '/api/store/spaces/install', { spaceId, projectId, force });
69	  storeApps = () => this.req('GET', '/api/apps');
70	  installApp = (appId, projectId, force = false) =>
71	    this.req('POST', '/api/apps/install', { appId, ...(projectId ? { projectId } : {}), force });
72	
73	  // ── project-app runtime ─────────────────────────────────────────────────
74	  appManifest = (projectId) => this.req('GET', `/api/projects/${projectId}/app`);
75	  appBuild = (projectId) => this.req('POST', `/api/projects/${projectId}/app/build`);
76	  appData = (projectId, table) => this.req('GET', `/api/projects/${projectId}/app/data/${table}`);
77	  appPage = (projectId, path = '') =>
78	    this.req('GET', `/app/${projectId}/${path}`, undefined, { raw: true });
79	
80	  // ── hooks & events ──────────────────────────────────────────────────────
81	  /** List every loaded hook across projects (`GET /api/hooks`). */
82	  listHooks = () => this.req('GET', '/api/hooks');
83	  /** POST to an app's own API route (`/app/<id>/api/<route>`) — the form-submit path. */
84	  appApi = (projectId, route, body, method = 'POST') =>
85	    this.req(method, `/app/${projectId}/api/${route}`, body, { raw: true });
86	  /** The one authoritative hook-run path (crond, boot catch-up and Studio all use it).
87	   *  The slug is a single path segment and may contain `:`/`@` (space hooks are
88	   *  `<spaceId>:<base>`; emitters are `@emitter:<scope>:<name>`) — encode it. */
89	  runHook = (projectId, slug) =>
90	    this.req('POST', `/api/projects/${projectId}/hooks/${encodeURIComponent(slug)}/run`, {});
91	  /** Run a cron emitter def by its pseudo-slug (`@emitter:<scope>:<name>`). */
92	  runEmitter = (projectId, scope, name) => this.runHook(projectId, `@emitter:${scope}:${name}`);
93	
94	  /**
95	   * Deliver an inbound webhook exactly as an external provider would.
96	   * `headers` carries the provider's signature headers — the pod verifies BEFORE emit.
97	   *
98	   * NOTE the bearer token: in prod the pod is reached through Envoy, which routes on the
99	   * gateway JWT's `sub` claim — without it the edge answers `401 Jwt is missing` and the
100	   * request never reaches the pod. The real public path (gateway `/api/inbound/<token>/<path>`)
101	   * is a 202 fire-and-forget broker that hides the pod's own status code, so a scenario that
102	   * needs to assert 200/401/404 + `{events:n}` must deliver to the pod directly. The pod
103	   * itself does no auth: verification is the provider signature, exactly as in production.
104	   */
105	  async inbound(path, body, headers = {}) {
106	    const payload = typeof body === 'string' ? body : JSON.stringify(body);
107	    // A scaled-to-zero pod answers the FIRST hit with `504 {waking:true}` (the Envoy
108	    // instant-wake activator) while it boots — that is not the def's real verdict. Retry
109	    // the exact same signed bytes until the woken pod actually runs verify→emit. The body
110	    // is byte-identical, but inbound dedupe only kicks in AFTER a successful verify, so a
111	    // retry of a request the pod never processed is not deduped.
112	    for (let attempt = 0; ; attempt++) {
113	      const res = await fetch(`${this.base}/api/inbound/${path}`, {
114	        method: 'POST',
115	        headers: {
116	          'content-type': 'application/json',
117	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
118	          ...headers,
119	        },
120	        body: payload,
121	      });
122	      const text = await res.text();
123	      let parsed = text;
124	      try {
125	        parsed = JSON.parse(text);
126	      } catch {
127	        /* raw */
128	      }
129	      const waking = res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
130	      if (!waking || attempt >= 20) return { status: res.status, body: parsed };
131	      await new Promise((r) => setTimeout(r, 3000));
132	    }
133	  }
134	
135	  // ── uploads (chat attachments) ──────────────────────────────────────────
136	  /**
137	   * Upload a local file as a chat attachment (the UI's "load a file" action).
138	   * `POST /api/uploads` takes base64 + mediaType and returns an AttachmentRef
139	   * (`{id, kind, mediaType, filename?, url}`) that a message then references by id.
140	   * Pair with `ThingSession.sendWithAttachments()` (WS path — HTTP /message drops attachments).
141	   */
142	  async upload(filePath, { mediaType, filename } = {}) {
143	    const { readFileSync } = await import('node:fs');
144	    const { basename, extname } = await import('node:path');
145	    const bytes = readFileSync(filePath);
146	    const ext = extname(filePath).toLowerCase();
147	    const mt =
148	      mediaType ??
149	      (ext === '.md'
150	        ? 'text/markdown'
151	        : ext === '.txt'
152	          ? 'text/plain'
153	          : ext === '.pdf'
154	            ? 'application/pdf'
155	            : ext === '.csv'
156	              ? 'text/csv'
157	              : 'application/octet-stream');
158	    return this.req('POST', '/api/uploads', {
159	      filename: filename ?? basename(filePath),
160	      mediaType: mt,
161	      data: bytes.toString('base64'),
162	    });
163	  }
164	
165	  // ── env / lifecycle ─────────────────────────────────────────────────────
166	  getEnv = () => this.req('GET', '/api/env');
167	  /** Restart the pod process (used by the auto-resume scenario). Pod exits ~100ms later. */
168	  restart = () => this.req('POST', '/api/restart', {}).catch(() => ({ ok: true }));
169	}
