129	/** Sum of every numeric stock/qty field across materials+products — proves stock actually moved. */
130	async function stockSum(pod, projectId, tables = ['materials', 'products', 'stock', 'inventory']) {
131	  let sum = 0;
132	  for (const t of tables) {
133	    const rows = (await pod.appData(projectId, t).catch(() => ({ rows: [] }))).rows ?? [];
134	    for (const row of rows) {
135	      for (const [k, v] of Object.entries(row ?? {})) {
136	        // Seeded CSV values can be numeric STRINGS — coerce so stock actually counts.
137	        const n = typeof v === 'number' ? v : typeof v === 'string' && /^-?\d+(\.\d+)?$/.test(v.trim()) ? Number(v) : NaN;
138	        if (/qty|stock|quantity|count|on_hand|remaining|units/i.test(k) && Number.isFinite(n)) sum += n;
139	      }
140	    }
141	  }
142	  return sum;
143	}
144	/** Poll for a predicate over the current db blob to become true (headless hook→agent chains are async). */
145	async function waitForDb(pod, projectId, pred, { tries = 20, ms = 6_000 } = {}) {
146	  for (let i = 0; i < tries; i++) {
147	    const names = await tableNames(pod, projectId);
148	    const blob = await dbBlob(pod, projectId, names);
149	    if (pred(blob, names)) return { hit: true, blob, names };
150	    await sleep(ms);
151	  }
152	  const names = await tableNames(pod, projectId);
153	  return { hit: false, blob: await dbBlob(pod, projectId, names), names };
154	}
