import { mintSession } from './lib/jwt.mjs';
import { Pod } from './lib/pod.mjs';
import { createHmac } from 'node:crypto';
import fs from 'node:fs';
const u = JSON.parse(fs.readFileSync('.state/users/09-home-renovation.json','utf8'));
const s = mintSession(u.userId, u.email);
const pod = new Pod({ base:'https://lmthing.chat', token:s.accessToken });
await pod.listProjects();
const secret='home-reno-demo-hmac-secret';
const si=(body)=>{const raw=JSON.stringify(body);const sig='sha256='+createHmac('sha256',secret).update(raw).digest('hex');return pod.inbound('demo',raw,{'x-demo-signature':sig});};
const N=15;
const res = await Promise.all(Array.from({length:N},(_,i)=>si({message:{message_id:2000+i,text:`SPROBE-${i}`,chat:{id:'c1'},from:{id:'u1',username:'niko'}}}).catch(e=>({status:e?.status??0,body:String(e).slice(0,80)}))));
const dist={};
for(const r of res){const k=`${r.status}/events:${r.body&&r.body.events!==undefined?r.body.events:JSON.stringify(r.body).slice(0,40)}`;dist[k]=(dist[k]||0)+1;}
console.log('distribution:', JSON.stringify(dist,null,0));
EOF
node _storm.mjs 2>&1 | tail -4; rm -f _storm.mjs

